`,r.jsx(n.p,{children:"This is enough for summarization, rewriting, brainstorming, explanation, and many lightweight support flows."}),`
`,r.jsx(n.h3,{id:"workflow",children:r.jsx(n.a,{href:"#workflow",children:"Workflow"})}),`
`,r.jsx(n.p,{children:"A workflow is a fixed sequence of steps. The application decides the path, and the model performs narrow jobs inside that path."}),`
`,r.jsx(or,{nodes:["Classify","Retrieve","Generate","Validate","Send"],caption:"The application owns every transition, retry policy, and timeout."}),`
`,r.jsx(n.p,{children:"Workflows are underrated. If the path is known ahead of time, use a workflow. It is easier to test, cheaper to run, and easier to explain in an incident review."}),`
`,r.jsx(n.h3,{id:"agent",children:r.jsx(n.a,{href:"#agent",children:"Agent"})}),`
`,r.jsx(n.p,{children:"An agent has some control over the path. It can choose tools, decide whether it needs more information, loop over intermediate results, and stop when the task is complete."}),`
`,r.jsx(dd,{left:{title:"Loaded context",body:"User goal, state, docs, permissions"},center:"Model decision engine",right:[{title:"Answer user"},{title:"Search documents"},{title:"Call safe API"},{title:"Ask clarification"},{title:"Stop"}],caption:"The model chooses from a bounded action surface. The application validates and executes."}),`
`,r.jsx(n.p,{children:'That autonomy should be scoped. A production agent should not be "a model that can do anything." It should be "a model that can choose from a small set of safe actions to accomplish a specific job."'}),`
`,r.jsx(n.p,{children:"The smaller the job, the better the agent."}),`
